### Extend DecoratorNode using legacy static methods

Source: https://github.com/facebook/lexical/blob/main/packages/lexical-website/docs/concepts/nodes.mdx

Illustrates extending DecoratorNode using legacy static methods like `getType`, `clone`, `importJSON`, and `exportJSON`. This approach is useful for maintaining backward compatibility or when the $config method is not preferred. It defines a SerializedVideoNode for JSON serialization.

```typescript
import {
  DecoratorNode,
  type EditorConfig,
  type LexicalNode,
  type SerializedLexicalNode,
  type Spread,
} from 'lexical';

export type SerializedVideoNode = Spread<
  {
    id: string;
  },
  SerializedLexicalNode
>;

export class VideoNode extends DecoratorNode<ReactNode> {
  __id: string;

  static getType(): string {
    return 'video';
  }

  static clone(node: VideoNode): VideoNode {
    return new VideoNode(node.__id, node.__key);
  }

  static importJSON(serializedNode: SerializedVideoNode): VideoNode {
    return new VideoNode(serializedNode.id).updateFromJSON(serializedNode);
  }

  constructor(id: string, key?: NodeKey) {
    super(key);
    this.__id = id;
  }

  exportJSON(): SerializedVideoNode {
    return {...super.exportJSON(), id: this.__id};
  }

  createDOM(): HTMLElement {
    return document.createElement('div');
  }

  updateDOM(): false {
    return false;
  }

  decorate(): ReactNode {
    return <VideoPlayer videoID={this.__id} />;
  }
}

export function $createVideoNode(id: string): VideoNode {
  return $applyNodeReplacement(new VideoNode(id));
}

export function $isVideoNode(
  node: LexicalNode | null | undefined,
): node is VideoNode {
  return node instanceof VideoNode;
}
```

